// Both classes have a quack method — same 'interface'
class Duck {
  quack() {
    return 'Quack!';
  }
}

class RobotDuck {
  constructor(battery) {
    this.battery = battery;
  }
  quack() {
    return 'Beep Quack! Battery at ' + this.battery + '%';
  }
}

// This function accepts anything with a quack method
function makeItQuack(animal) {
  if (typeof animal.quack !== 'function') {
    throw new Error('No quack method found');
  }
  console.log(animal.quack());
}

makeItQuack(new Duck());
// Expected output: Quack!
makeItQuack(new RobotDuck(85));
// Expected output: Beep Quack! Battery at 85%
